(() => {
  "use strict";
  const K={projects:"nexus-v9-projects",active:"nexus-v9-active-project",tasks:"nexus-v9-tasks",compare:"nexus-v9-compare",doc:"nexus-v9-doc-context",ui:"nexus-v9-ui",voice:"nexus-v9-voice"};
  const S={view:"dashboard",config:{},account:null,projects:load(K.projects,[]),tasks:load(K.tasks,[]),compare:load(K.compare,[]),docs:[],docContext:sessionStorage.getItem(K.doc)||"",recognition:null,listening:false,canvas:null};
  document.addEventListener("DOMContentLoaded",init);
  async function init(){createHub();applyUI();gestures();await Promise.all([config(),account()]);watchTasks();window.NEXUS_PRO={open,close,getActiveProjectId,getProjectContext,getDocumentContext:()=>S.docContext,ingestFile,saveGeneratedImage,rateMessage,reportMessage,branchFromMessage,addToCompare,saveLibraryItem,refreshAccount:account}}
  function createHub(){const b=document.createElement("div");b.id="proHubBackdrop";b.className="pro-backdrop";b.hidden=true;b.innerHTML=`<section class="pro-shell" role="dialog" aria-modal="true"><nav class="pro-nav" id="proNav"><div class="pro-brand"><img src="/assets/logo-icon.png?v=15.1.0"><div><strong>NEXUS PRO</strong><small>Production V15.1.0</small></div></div>${nav("dashboard","◈","Dashboard")}${nav("projects","▤","Projects")}${nav("library","▣","Library")}${nav("tasks","◷","Scheduled")}${nav("integrations","⌁","Integrations")}${nav("documents","PDF","Document AI")}${nav("voice","🎙","Voice")}${nav("images","▧","Image Lab")}${nav("security","🛡","Security")}${nav("admin","📊","Admin")}${nav("interface","⚙","Interface")}<div class="pro-nav-spacer"></div></nav><main class="pro-main"><header class="pro-header"><div><h2 id="proTitle">Nexus Pro</h2><p id="proSubtitle">Advanced AI workspace</p></div><button class="pro-close" id="proClose">✕</button></header><section class="pro-view" id="proView"></section></main></section>`;b.onclick=e=>{if(e.target===b)close()};document.body.appendChild(b);const proCloseButton=b.querySelector("#proClose"),proNavigation=b.querySelector("#proNav");if(proCloseButton)proCloseButton.onclick=close;if(proNavigation)proNavigation.onclick=e=>{const x=e.target.closest("[data-pro-view]");if(x)render(x.dataset.proView)};document.addEventListener("keydown",e=>{if(e.key==="Escape"&&!b.hidden)close();if((e.ctrlKey||e.metaKey)&&e.shiftKey&&e.key.toLowerCase()==="p"){e.preventDefault();open("projects")}if((e.ctrlKey||e.metaKey)&&e.shiftKey&&e.key.toLowerCase()==="l"){e.preventDefault();open("library")}})}
  function nav(v,i,l){return`<button data-pro-view="${v}"><span>${i}</span><span>${l}</span></button>`}
  function open(v="dashboard"){proHubBackdrop.hidden=false;document.body.style.overflow="hidden";render(v)}function close(){proHubBackdrop.hidden=true;document.body.style.overflow=""}
  function render(v){S.view=v;const t={dashboard:["Quantum Dashboard","Projects, files, schedules, integrations and intelligence"],projects:["Real Projects","Instructions, memory, chats, files and lifecycle controls"],library:["Advanced Library","Search every generated and uploaded asset"],tasks:["Scheduled AI Tasks","Reminders, research, news and project checks"],integrations:["Plugins & Integrations","Google Workspace, GitHub, Notion, Slack, Discord and Telegram"],documents:["Advanced Document Intelligence","Multi-PDF search, OCR, citations and comparison"],voice:["Real-time Voice","Continuous listening, wake word, voices and interruption"],images:["Advanced Image Lab","Background tools, OCR, enhancement and AI editing"],security:["Account Security","Verification, recovery and active sessions"],admin:["Security & Admin","Users, limits, logs, reports and maintenance"],interface:["Interface Lab","Language, accent, shortcuts and responsive controls"]}[v]||["Nexus Pro",""];proTitle.textContent=t[0];proSubtitle.textContent=t[1];document.querySelectorAll("[data-pro-view]").forEach(x=>x.classList.toggle("active",x.dataset.proView===v));({dashboard,projects,library,tasks,integrations,documents,voice,images,security,admin,interface:interfaceView}[v]||dashboard)(proView)}

  function dashboard(el){const p=activeProject(),cards=[["▤","Real Projects",`${S.projects.filter(x=>!x.archived).length} active projects`,"projects"],["▣","Advanced Library","Images, PDFs, code, shares, favorites and media","library"],["◷","Scheduled Tasks",`${S.tasks.filter(x=>x.enabled).length} enabled tasks`,"tasks"],["⌁","Integrations","Connect external services securely","integrations"],["PDF","Document AI","Multi-file page citations and OCR","documents"],["🎙","Voice Mode","Wake word, continuous listening and voices","voice"],["▧","Image Lab","Local editing plus optional AI provider","images"],["🛡","Security","Sessions, verification and password recovery","security"],["📊","Admin","Limits, reports, logs and maintenance","admin"]];el.innerHTML=`<div class="pro-status ${p?"ok":""}">${p?`Active project: ${esc(p.icon)} ${esc(p.name)}`:"No active project. Chats use the general workspace."}</div><div class="pro-grid" id="dashGrid" style="margin-top:12px"></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Quick controls</h3></div><div class="pro-buttons"><button class="pro-primary" id="newProjectQuick">＋ New project</button><button class="pro-secondary" id="duplicateChat">Duplicate chat</button><button class="pro-secondary" id="compareQuick">Compare answers (${S.compare.length})</button><button class="pro-secondary" id="notifyQuick">Enable notifications</button></div></div>`;cards.forEach(c=>{const x=document.createElement("button");x.className="pro-card";x.innerHTML=`<span class="pro-card-icon">${c[0]}</span><h3>${c[1]}</h3><p>${c[2]}</p>`;x.onclick=()=>render(c[3]);dashGrid.appendChild(x)});newProjectQuick.onclick=()=>render("projects");duplicateChat.onclick=()=>{window.NEXUS_APP?.duplicateActiveChat?.();toast("Conversation duplicated.");close()};compareQuick.onclick=compareView;notifyQuick.onclick=notifyPermission}

  function projects(el){const a=getActiveProjectId(),visible=S.projects.filter(p=>!p.archived);el.innerHTML=`<div class="pro-row"><form class="pro-card pro-stack" id="projectForm"><h3>Create project</h3><div class="pro-row"><label class="pro-field"><span>Icon</span><input id="pIcon" value="🚀" maxlength="4"></label><label class="pro-field"><span>Name</span><input id="pName" required maxlength="70"></label></div><label class="pro-field"><span>Project instructions</span><textarea id="pInstructions" rows="4"></textarea></label><label class="pro-field"><span>Project-specific memory</span><textarea id="pMemory" rows="3"></textarea></label><button class="pro-primary">Create project</button></form><div class="pro-card"><h3>Active project controls</h3><p>New chats inherit the active project. Existing chats can be assigned.</p><div class="pro-buttons" style="margin-top:12px"><button class="pro-secondary" id="newProjectChat">New project chat</button><button class="pro-secondary" id="assignChat">Assign current chat</button><button class="pro-secondary" id="clearProject">General workspace</button></div></div></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Projects</h3><button class="pro-secondary" id="archivedProjects">Archived</button></div><div class="pro-grid" id="projectGrid"></div></div>`;
    projectForm.onsubmit=async e=>{e.preventDefault();const p={id:crypto.randomUUID(),icon:pIcon.value.trim()||"🚀",name:pName.value.trim(),instructions:pInstructions.value.trim(),memory:pMemory.value.trim(),chatIds:[],fileIds:[],archived:false,createdAt:Date.now(),updatedAt:Date.now()};S.projects.unshift(p);saveProjects();setActive(p.id);await syncProject(p);projects(el)};newProjectChat.onclick=()=>{if(!getActiveProjectId())return toast("Choose a project first.","error");window.NEXUS_APP?.createChat?.(true);close()};assignChat.onclick=()=>{const id=getActiveProjectId(),chat=window.NEXUS_APP?.getActiveChat?.();if(!id||!chat)return toast("Select a project and active chat.","error");chat.projectId=id;const p=S.projects.find(x=>x.id===id);if(p&&!p.chatIds.includes(chat.id))p.chatIds.push(chat.id);window.NEXUS_APP?.saveChats?.();saveProjects();syncProject(p);toast("Chat assigned.")};clearProject.onclick=()=>{setActive("");projects(el)};archivedProjects.onclick=()=>archived(el);if(!visible.length)projectGrid.innerHTML='<div class="pro-status">No projects yet.</div>';visible.forEach(p=>{const chats=(window.NEXUS_APP?.getChats?.()||[]).filter(c=>c.projectId===p.id),c=document.createElement("div");c.className=`pro-card project-card ${p.id===a?"active":""}`;c.innerHTML=`<span class="project-icon">${esc(p.icon)}</span><h3>${esc(p.name)}</h3><p>${esc(p.instructions||"No custom instructions")}</p><small>${chats.length} chats · ${p.fileIds?.length||0} files</small><div class="pro-buttons" style="margin-top:11px"><button class="pro-primary act">${p.id===a?"Active":"Open"}</button><button class="pro-secondary edit">Edit</button><button class="pro-secondary chats">Chats</button><button class="pro-danger arc">Archive</button></div>`;c.querySelector(".act").onclick=()=>{setActive(p.id);projects(el)};c.querySelector(".edit").onclick=()=>editProject(p,el);c.querySelector(".chats").onclick=()=>projectChats(p,el);c.querySelector(".arc").onclick=async()=>{p.archived=true;p.updatedAt=Date.now();saveProjects();await syncProject(p);projects(el)};projectGrid.appendChild(c)})}
  function editProject(p,el){el.innerHTML=`<form class="pro-card pro-stack" id="editP"><h3>Edit ${esc(p.name)}</h3><div class="pro-row"><label class="pro-field"><span>Icon</span><input id="eIcon" value="${attr(p.icon)}"></label><label class="pro-field"><span>Name</span><input id="eName" value="${attr(p.name)}" required></label></div><label class="pro-field"><span>Instructions</span><textarea id="eInstructions" rows="5">${esc(p.instructions||"")}</textarea></label><label class="pro-field"><span>Memory</span><textarea id="eMemory" rows="4">${esc(p.memory||"")}</textarea></label><div class="pro-buttons"><button class="pro-primary">Save</button><button class="pro-secondary" type="button" id="eCancel">Cancel</button><button class="pro-danger" type="button" id="eDelete">Delete permanently</button></div></form>`;eCancel.onclick=()=>projects(el);eDelete.onclick=async()=>{if(!confirm(`Delete ${p.name}?`))return;(window.NEXUS_APP?.getChats?.()||[]).forEach(c=>{if(c.projectId===p.id)c.projectId=""});window.NEXUS_APP?.saveChats?.();S.projects=S.projects.filter(x=>x.id!==p.id);if(getActiveProjectId()===p.id)setActive("");saveProjects();await delCloud("/api/projects",p.id);projects(el)};editP.onsubmit=async e=>{e.preventDefault();Object.assign(p,{icon:eIcon.value.trim()||"🚀",name:eName.value.trim(),instructions:eInstructions.value.trim(),memory:eMemory.value.trim(),updatedAt:Date.now()});saveProjects();await syncProject(p);projects(el)}}
  function projectChats(p,el){const chats=(window.NEXUS_APP?.getChats?.()||[]).filter(c=>c.projectId===p.id);el.innerHTML=`<div class="pro-section-head"><h3>${esc(p.icon)} ${esc(p.name)} chats</h3><button class="pro-secondary" id="backP">Back</button></div><div class="pro-list" id="pChats"></div>`;backP.onclick=()=>projects(el);if(!chats.length)pChats.innerHTML='<div class="pro-status">No chats assigned.</div>';chats.forEach(c=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(c.title)}</strong><small>${c.messages.length} messages</small></div><div class="pro-buttons"><button class="pro-primary open">Open</button><button class="pro-secondary remove">Remove</button></div>`;r.querySelector(".open").onclick=()=>{window.NEXUS_APP?.setActiveChat?.(c.id);close()};r.querySelector(".remove").onclick=()=>{c.projectId="";window.NEXUS_APP?.saveChats?.();projectChats(p,el)};pChats.appendChild(r)})}
  function archived(el){const arr=S.projects.filter(p=>p.archived);el.innerHTML=`<div class="pro-section-head"><h3>Archived projects</h3><button class="pro-secondary" id="backP">Back</button></div><div class="pro-list" id="arcList"></div>`;backP.onclick=()=>projects(el);if(!arr.length)arcList.innerHTML='<div class="pro-status">No archived projects.</div>';arr.forEach(p=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(p.icon)} ${esc(p.name)}</strong><small>Archived</small></div><button class="pro-primary">Restore</button>`;r.querySelector("button").onclick=async()=>{p.archived=false;saveProjects();await syncProject(p);archived(el)};arcList.appendChild(r)})}

  async function library(el){const local=await libList(),fav=load("nexus-v8-favorites",[]).map(x=>({id:`fav-${x.id}`,category:"favorite",name:"Favorite answer",text:x.content,createdAt:x.createdAt})),shared=(window.NEXUS_APP?.getChats?.()||[]).filter(c=>String(c.title).startsWith("[Shared]")).map(c=>({id:`share-${c.id}`,category:"shared",name:c.title,text:c.messages.map(m=>`${m.role}: ${m.content}`).join("\n\n"),createdAt:c.updatedAt})),all=[...local,...fav,...shared];el.innerHTML=`<div class="pro-filterbar"><input id="libSearch" placeholder="Search library"><select id="libCat"><option value="all">All categories</option><option value="image">Generated images</option><option value="pdf">PDFs</option><option value="code">Code</option><option value="shared">Shared</option><option value="favorite">Favorites</option><option value="video">Videos</option><option value="music">Music</option><option value="file">Other files</option></select><label class="pro-primary" style="display:grid;place-items:center;cursor:pointer">Upload<input type="file" id="libUpload" hidden multiple></label></div><div class="pro-grid" id="libGrid"></div><div class="pro-section" style="margin-top:17px"><div class="pro-section-head"><h3>Preview</h3></div><div class="pro-preview" id="libPreview">Select an item.</div></div>`;const draw=()=>{const q=libSearch.value.toLowerCase(),cat=libCat.value,arr=all.filter(x=>(cat==="all"||x.category===cat)&&(!q||`${x.name} ${x.text||""}`.toLowerCase().includes(q)));libGrid.innerHTML="";if(!arr.length)libGrid.innerHTML='<div class="pro-status">No matching items.</div>';arr.forEach(x=>{const c=document.createElement("button");c.className="pro-card";c.innerHTML=`<span class="pro-card-icon">${catIcon(x.category)}</span><h3>${esc(x.name)}</h3><p>${esc(x.category)} · ${date(x.createdAt)}</p>`;c.onclick=()=>preview(x,libPreview);libGrid.appendChild(c)})};libSearch.oninput=draw;libCat.onchange=draw;libUpload.onchange=async e=>{for(const f of e.target.files)await ingestFile(f);library(el)};draw()}
  function preview(x,p){p.innerHTML="";if(x.dataUrl&&x.category==="image"){p.innerHTML=`<img src="${x.dataUrl}"><div class="pro-buttons" style="margin-top:10px"><button class="pro-primary use">Attach</button><button class="pro-danger del">Delete</button></div>`;p.querySelector(".use").onclick=async()=>{await window.NEXUS_APP?.handleFile?.(dataFile(x.dataUrl,x.name||"image.png"));close()};p.querySelector(".del").onclick=async()=>{await libDelete(x.id);render("library")}}else{p.textContent=x.text||`${x.name}\n${x.mime||""}\n${bytes(x.size||0)}`;const b=document.createElement("div");b.className="pro-buttons";b.style.marginTop="10px";const u=document.createElement("button");u.className="pro-primary";u.textContent="Use in chat";u.onclick=()=>{window.NEXUS_APP?.setPrompt?.(`Use this library item:\n\n--- ${x.name} ---\n${x.text||""}`);close()};b.appendChild(u);if(!String(x.id).startsWith("fav-")&&!String(x.id).startsWith("share-")){const d=document.createElement("button");d.className="pro-danger";d.textContent="Delete";d.onclick=async()=>{await libDelete(x.id);render("library")};b.appendChild(d)}p.appendChild(b)}}

  function tasks(el){el.innerHTML=`<div class="pro-row"><form class="pro-card pro-stack" id="taskForm"><h3>Create scheduled AI task</h3><label class="pro-field"><span>Name</span><input id="tName" required></label><div class="pro-row"><label class="pro-field"><span>Type</span><select id="tType"><option value="reminder">Reminder</option><option value="research">Scheduled research</option><option value="news">Daily news summary</option><option value="project">Project check</option></select></label><label class="pro-field"><span>Schedule</span><select id="tSchedule"><option value="once">Once</option><option value="daily">Daily</option><option value="weekly">Weekly</option></select></label></div><label class="pro-field"><span>Date and time</span><input id="tTime" type="datetime-local" required></label><label class="pro-field"><span>Instruction</span><textarea id="tPrompt" rows="4" required></textarea></label><label class="pro-field"><span>Delivery</span><select id="tDelivery"><option value="notification">Browser notification</option><option value="email">Email</option><option value="telegram">Telegram</option><option value="discord">Discord</option><option value="slack">Slack</option></select></label><button class="pro-primary">Save task</button></form><div class="pro-card"><h3>Background execution</h3><p>Browser reminders work while AI NEXUS is open. True recurring research/delivery uses the included Cloudflare Cron Worker.</p><div class="pro-buttons" style="margin-top:12px"><button class="pro-secondary" id="allowNotify">Enable notifications</button><button class="pro-secondary" id="syncTasks">Sync cloud</button></div></div></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Your tasks</h3></div><div class="pro-list" id="taskList"></div></div>`;const n=new Date(Date.now()+3600000);n.setMinutes(0,0,0);tTime.value=localTime(n);taskForm.onsubmit=async e=>{e.preventDefault();const t={id:crypto.randomUUID(),name:tName.value.trim(),type:tType.value,schedule:tSchedule.value,nextRun:new Date(tTime.value).getTime(),prompt:tPrompt.value.trim(),delivery:tDelivery.value,enabled:true,lastRun:0,createdAt:Date.now()};S.tasks.unshift(t);saveTasks();await syncTask(t);tasks(el)};allowNotify.onclick=notifyPermission;syncTasks.onclick=async()=>{for(const t of S.tasks)await syncTask(t);toast("Tasks synced.")};drawTasks(taskList,el)}
  function drawTasks(list,el){list.innerHTML="";if(!S.tasks.length)list.innerHTML='<div class="pro-status">No scheduled tasks.</div>';S.tasks.sort((a,b)=>a.nextRun-b.nextRun).forEach(t=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(t.name)} <span class="task-badge">${esc(t.schedule)}</span></strong><small>${esc(t.type)} · ${dateTime(t.nextRun)} · ${esc(t.delivery)}</small></div><div class="pro-buttons"><button class="pro-secondary toggle">${t.enabled?"Pause":"Resume"}</button><button class="pro-primary run">Run</button><button class="pro-danger del">Delete</button></div>`;r.querySelector(".toggle").onclick=()=>{t.enabled=!t.enabled;saveTasks();syncTask(t);drawTasks(list,el)};r.querySelector(".run").onclick=()=>runTask(t);r.querySelector(".del").onclick=async()=>{S.tasks=S.tasks.filter(x=>x.id!==t.id);saveTasks();await delCloud("/api/tasks",t.id);drawTasks(list,el)};list.appendChild(r)})}
  async function runTask(t){if(t.type==="reminder"){notify(t.name,t.prompt);t.lastRun=Date.now();advance(t);saveTasks();return}try{const d=await api("/api/tasks",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"run",task:t})});notify(t.name,d.result||"Task completed.");t.lastRun=Date.now();advance(t);saveTasks();toast("Task completed.")}catch(e){window.NEXUS_APP?.setPrompt?.(t.prompt);close();toast(`Server run unavailable; prompt loaded: ${e.message}`,"error")}}

  async function integrations(el){let st={integrations:{}};try{st=await api("/api/integrations?action=status")}catch{}const arr=[["google","G","Google Workspace","Private Drive, Gmail and Calendar"],["github","◉","GitHub","Read repositories and code"],["notion","N","Notion","Search pages and databases"],["slack","S","Slack","Send webhook messages"],["discord","D","Discord","Send webhook messages"],["telegram","T","Telegram","Send bot messages"]];el.innerHTML=`<div class="pro-status">Keys stay in Cloudflare Secrets. Never put private tokens in frontend JavaScript.</div><div class="pro-grid" id="intGrid" style="margin-top:12px"></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Integration console</h3></div><div class="pro-preview" id="intOut">Choose an integration.</div></div>`;arr.forEach(a=>{const c=document.createElement("div"),ok=!!st.integrations?.[a[0]];c.className="pro-card";c.innerHTML=`<span class="pro-card-icon">${a[1]}</span><h3>${a[2]}</h3><p>${a[3]}</p><small>${ok?"Configured":"Setup required"}</small><div class="pro-buttons" style="margin-top:10px"><button class="pro-primary">${ok?"Open":"Setup"}</button></div>`;c.querySelector("button").onclick=()=>intConsole(a[0],a[2],intOut);intGrid.appendChild(c)})}
  function intConsole(id,name,out){const forms={github:`<label class="pro-field"><span>Repository</span><input id="iRepo" value="MARKZOSUF/my-portfolio"></label><label class="pro-field"><span>Path</span><input id="iPath"></label>`,google:`<label class="pro-field"><span>Service</span><select id="iService"><option value="drive">Private Drive</option><option value="gmail">Recent Gmail</option><option value="calendar">Calendar</option></select></label>`,notion:`<label class="pro-field"><span>Search</span><input id="iQuery"></label>`,slack:`<label class="pro-field"><span>Message</span><textarea id="iMessage"></textarea></label>`,discord:`<label class="pro-field"><span>Message</span><textarea id="iMessage"></textarea></label>`,telegram:`<label class="pro-field"><span>Message</span><textarea id="iMessage"></textarea></label>`};out.innerHTML=`<div class="pro-stack"><h3>${name}</h3>${forms[id]}<button class="pro-primary" id="iRun">Run</button><div id="iResult"></div></div>`;iRun.onclick=async()=>{iResult.textContent="Working…";try{const p={integration:id};if(id==="github"){p.repo=iRepo.value;p.path=iPath.value}else if(id==="google")p.service=iService.value;else if(id==="notion")p.query=iQuery.value;else p.message=iMessage.value;iResult.textContent=JSON.stringify(await api("/api/integrations",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p)}),null,2)}catch(e){iResult.textContent=e.message}}}

  function documents(el){el.innerHTML=`<div class="pro-row"><div class="pro-card pro-stack"><h3>Upload multiple PDFs</h3><label class="pro-primary" style="display:grid;place-items:center;cursor:pointer">Choose PDFs<input id="docUpload" type="file" accept=".pdf,application/pdf" multiple hidden></label><button class="pro-secondary" id="docOcr">OCR scanned pages</button><button class="pro-secondary" id="docVisual">Analyze first page image</button><div class="pro-status" id="docStatus">No documents loaded.</div></div><div class="pro-card pro-stack"><h3>Vector search and citations</h3><label class="pro-field"><span>Question</span><textarea id="docQuery" rows="4"></textarea></label><div class="pro-buttons"><button class="pro-primary" id="docSearch">Search pages</button><button class="pro-secondary" id="docAsk">Ask AI</button><button class="pro-secondary" id="docCompare">Compare documents</button></div></div></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Loaded documents</h3><button class="pro-danger" id="docClear">Clear</button></div><div class="pro-list" id="docList"></div></div><div class="pro-section"><div class="pro-section-head"><h3>Results</h3></div><div class="doc-results" id="docResults"></div></div>`;docUpload.onchange=async e=>{docStatus.textContent="Extracting pages…";for(const f of e.target.files)await extractPdf(f,docStatus);drawDocs(el);docStatus.textContent=`${S.docs.length} documents · ${S.docs.reduce((n,d)=>n+d.pages.length,0)} pages`};docSearch.onclick=()=>searchDocs(docQuery.value,docResults);docAsk.onclick=()=>askDocs(docQuery.value,docResults);docCompare.onclick=compareDocs;docOcr.onclick=()=>ocrDocs(docStatus);docVisual.onclick=visualPage;docClear.onclick=()=>{S.docs=[];S.docContext="";sessionStorage.removeItem(K.doc);documents(el)};drawDocs(el)}
  function drawDocs(el){const l=el.querySelector("#docList");if(!l)return;l.innerHTML="";if(!S.docs.length)l.innerHTML='<div class="pro-status">No documents loaded.</div>';S.docs.forEach(d=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(d.name)}</strong><small>${d.pages.length} pages · ${bytes(d.size)}</small></div><button class="pro-danger">Remove</button>`;r.querySelector("button").onclick=()=>{S.docs=S.docs.filter(x=>x.id!==d.id);drawDocs(el)};l.appendChild(r)})}
  async function extractPdf(file,status){const pdfjs=await import("/assets/vendor/pdf-4.10.38.min.mjs?v=15.1.0");pdfjs.GlobalWorkerOptions.workerSrc="/assets/vendor/pdf-worker-4.10.38.min.mjs?v=15.1.0";const raw=new Uint8Array(await file.arrayBuffer()),pdf=await pdfjs.getDocument({data:raw}).promise,d={id:crypto.randomUUID(),name:file.name,size:file.size,pages:[],raw,createdAt:Date.now()};for(let p=1;p<=pdf.numPages;p++){status.textContent=`${file.name}: page ${p}/${pdf.numPages}`;const page=await pdf.getPage(p),ct=await page.getTextContent(),text=ct.items.map(x=>x.str).join(" ").replace(/\s+/g," ").trim();d.pages.push({page:p,text,vector:vec(text)})}S.docs.push(d);await saveLibraryItem({category:"pdf",name:file.name,size:file.size,mime:"application/pdf",text:d.pages.map(p=>`[Page ${p.page}] ${p.text}`).join("\n\n")})}
  function searchDocs(q,c){c.innerHTML="";if(!q.trim()||!S.docs.length){c.innerHTML='<div class="pro-status">Load documents and enter a query.</div>';return[]}const v=vec(q),r=[];S.docs.forEach(d=>d.pages.forEach(p=>{const s=cos(v,p.vector);if(s>0)r.push({d,p,s})}));r.sort((a,b)=>b.s-a.s);const top=r.slice(0,8);top.forEach(x=>{const z=document.createElement("div");z.className="doc-result";z.innerHTML=`<strong>${esc(x.d.name)} <span class="doc-citation">p.${x.p.page}</span></strong><small> relevance ${(x.s*100).toFixed(1)}%</small><p>${esc(x.p.text.slice(0,850))}</p>`;c.appendChild(z)});S.docContext=top.map(x=>`[${x.d.name} p.${x.p.page}] ${x.p.text}`).join("\n\n").slice(0,50000);sessionStorage.setItem(K.doc,S.docContext);return top}
  function askDocs(q,c){const top=searchDocs(q,c);if(!top.length)return;const context=top.map(x=>`[${x.d.name} p.${x.p.page}] ${x.p.text}`).join("\n\n");window.NEXUS_APP?.setPrompt?.(`Answer only from these extracts. Cite exact [Document p.X] labels. If absent, say so.\n\nQuestion: ${q}\n\n${context}`);close()}
  function compareDocs(){if(S.docs.length<2)return toast("Load at least two PDFs.","error");const x=S.docs.slice(0,4).map(d=>`## ${d.name}\n${d.pages.map(p=>`[p.${p.page}] ${p.text}`).join("\n").slice(0,24000)}`).join("\n\n");window.NEXUS_APP?.setPrompt?.(`Compare these documents. Show agreements, differences, contradictions and conclusions with page citations.\n\n${x}`);close()}
  async function ocrDocs(status){if(!S.docs.length)return toast("Load a PDF first.","error");status.textContent="Loading OCR…";await script("https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js");const d=S.docs[0],pdfjs=await import("/assets/vendor/pdf-4.10.38.min.mjs?v=15.1.0");pdfjs.GlobalWorkerOptions.workerSrc="/assets/vendor/pdf-worker-4.10.38.min.mjs?v=15.1.0";const pdf=await pdfjs.getDocument({data:d.raw.slice()}).promise,limit=Math.min(pdf.numPages,5);for(let p=1;p<=limit;p++){status.textContent=`OCR page ${p}/${limit}`;const page=await pdf.getPage(p),vp=page.getViewport({scale:1.6}),canvas=document.createElement("canvas");canvas.width=vp.width;canvas.height=vp.height;await page.render({canvasContext:canvas.getContext("2d"),viewport:vp}).promise;const result=await Tesseract.recognize(canvas,"eng",{logger:()=>{}});if(result.data.text.trim()){d.pages[p-1].text=`${d.pages[p-1].text}\n${result.data.text}`.trim();d.pages[p-1].vector=vec(d.pages[p-1].text)}}status.textContent=`OCR completed for ${limit} pages.`}
  async function visualPage(){if(!S.docs.length)return toast("Load a PDF first.","error");const d=S.docs[0],pdfjs=await import("/assets/vendor/pdf-4.10.38.min.mjs?v=15.1.0");pdfjs.GlobalWorkerOptions.workerSrc="/assets/vendor/pdf-worker-4.10.38.min.mjs?v=15.1.0";const pdf=await pdfjs.getDocument({data:d.raw.slice()}).promise,page=await pdf.getPage(1),vp=page.getViewport({scale:1.5}),canvas=document.createElement("canvas");canvas.width=vp.width;canvas.height=vp.height;await page.render({canvasContext:canvas.getContext("2d"),viewport:vp}).promise;const blob=await new Promise(r=>canvas.toBlob(r,"image/png"));await window.NEXUS_APP?.handleFile?.(new File([blob],`${d.name}-page-1.png`,{type:"image/png"}));window.NEXUS_APP?.setPrompt?.("Analyze this PDF page visually. Explain tables, charts, diagrams and layout.");close()}

  function voice(el){const voices=speechSynthesis.getVoices(),v=load(K.voice,{continuous:false,wakeWord:"hey nexus",autoSend:false,rate:1,pitch:1,voice:""});el.innerHTML=`<div class="pro-card"><div class="voice-orb" id="voiceOrb">🎙</div><div class="pro-status" id="voiceStatus">Ready. Voice support depends on browser and microphone permission.</div><div class="pro-buttons" style="justify-content:center;margin-top:12px"><button class="pro-primary" id="voiceStart">Start</button><button class="pro-secondary" id="voiceStop">Stop / interrupt</button><button class="pro-secondary" id="voiceRead">Read last answer</button></div></div><div class="pro-grid two" style="margin-top:14px"><div class="pro-card pro-stack"><h3>Conversation controls</h3><label class="pro-field"><span>Wake word</span><input id="wakeWord" value="${attr(v.wakeWord)}"></label><label><input type="checkbox" id="voiceContinuous" ${v.continuous?"checked":""}> Continuous listening</label><label><input type="checkbox" id="voiceAuto" ${v.autoSend?"checked":""}> Auto-send after wake word</label></div><div class="pro-card pro-stack"><h3>Voice output</h3><label class="pro-field"><span>Voice</span><select id="voiceSelect">${voices.map(x=>`<option value="${attr(x.name)}" ${x.name===v.voice?"selected":""}>${esc(x.name)} (${esc(x.lang)})</option>`).join("")}</select></label><label class="pro-field"><span>Speed</span><input id="voiceRate" type="range" min=".5" max="2" step=".1" value="${v.rate}"></label><label class="pro-field"><span>Pitch</span><input id="voicePitch" type="range" min=".5" max="2" step=".1" value="${v.pitch}"></label><button class="pro-secondary" id="voiceSave">Save settings</button></div></div>`;voiceStart.onclick=()=>startVoice(el);voiceStop.onclick=stopVoice;voiceRead.onclick=speakLast;voiceSave.onclick=()=>{localStorage.setItem(K.voice,JSON.stringify({continuous:voiceContinuous.checked,wakeWord:wakeWord.value.trim().toLowerCase(),autoSend:voiceAuto.checked,rate:Number(voiceRate.value),pitch:Number(voicePitch.value),voice:voiceSelect.value}));toast("Voice settings saved.")}}
  async function startVoice(el){const R=window.SpeechRecognition||window.webkitSpeechRecognition;if(!R)return toast("Speech recognition is not supported.","error");try{await navigator.mediaDevices.getUserMedia({audio:{noiseSuppression:true,echoCancellation:true,autoGainControl:true}})}catch(e){return toast(e.message,"error")}stopVoice();const cfg=load(K.voice,{continuous:false,wakeWord:"hey nexus",autoSend:false}),r=new R();S.recognition=r;S.listening=true;r.continuous=true;r.interimResults=true;r.lang="en-IN";voiceOrb.classList.add("listening");voiceStatus.textContent="Listening…";let final="",timer;r.onresult=e=>{let interim="";for(let i=e.resultIndex;i<e.results.length;i++){const t=e.results[i][0].transcript;if(e.results[i].isFinal)final+=t+" ";else interim+=t}voiceStatus.textContent=(final+interim).trim()||"Listening…";clearTimeout(timer);timer=setTimeout(()=>{const text=final.trim(),low=text.toLowerCase(),wake=(cfg.wakeWord||"").toLowerCase();if(text&&(wake?low.includes(wake):true)){const command=wake?text.slice(low.indexOf(wake)+wake.length).trim():text;window.NEXUS_APP?.setPrompt?.(command);if(cfg.autoSend&&command)window.NEXUS_APP?.sendCurrent?.()}final=""},1200)};r.onerror=e=>voiceStatus.textContent=`Voice error: ${e.error}`;r.onend=()=>{if(S.listening&&cfg.continuous)try{r.start()}catch{}else voiceOrb.classList.remove("listening")};r.start()}
  function stopVoice(){S.listening=false;try{S.recognition?.stop()}catch{}S.recognition=null;speechSynthesis.cancel()}function speakLast(){const c=window.NEXUS_APP?.getActiveChat?.(),m=[...(c?.messages||[])].reverse().find(x=>x.role==="assistant"&&!x.pending);if(!m)return toast("No answer to read.","error");const v=load(K.voice,{rate:1,pitch:1,voice:""}),u=new SpeechSynthesisUtterance(m.content.replace(/[#*_`]/g,"")),voice=speechSynthesis.getVoices().find(x=>x.name===v.voice);if(voice)u.voice=voice;u.rate=v.rate;u.pitch=v.pitch;speechSynthesis.cancel();speechSynthesis.speak(u)}

  function images(el){el.innerHTML=`<div class="pro-row"><div class="pro-card pro-stack"><h3>Open image</h3><label class="pro-primary" style="display:grid;place-items:center;cursor:pointer">Choose image<input id="imgUpload" type="file" accept="image/*" hidden></label><div class="pro-buttons"><button class="pro-secondary" id="imgEnhance">Enhance</button><button class="pro-secondary" id="imgBg">Remove simple background</button><button class="pro-secondary" id="imgFace">Blur faces</button><button class="pro-secondary" id="imgOcr">Extract text</button></div><div class="pro-buttons"><button class="pro-secondary" id="imgInpaint">Object removal</button><button class="pro-secondary" id="imgOutpaint">Outpaint</button><button class="pro-secondary" id="imgCompare">Compare two images</button></div></div><div class="pro-card pro-stack"><h3>AI edit instruction</h3><label class="pro-field"><span>Describe edit</span><textarea id="imgPrompt" rows="5"></textarea></label><button class="pro-primary" id="imgAI">Run configured AI editor</button><div class="pro-status">Inpainting/outpainting needs IMAGE_EDIT_API_URL. Local enhancement, simple background removal, face blur and OCR work without it.</div></div></div><div class="image-canvas-wrap" style="margin-top:14px"><canvas id="imgCanvas"></canvas></div><div class="pro-buttons" style="margin-top:10px"><button class="pro-primary" id="imgDownload">Download</button><button class="pro-secondary" id="imgLibrary">Save to Library</button></div><div class="pro-preview" id="imgOutput" style="margin-top:12px">Choose an image.</div>`;S.canvas=imgCanvas;imgUpload.onchange=e=>loadCanvas(e.target.files[0],imgCanvas);imgEnhance.onclick=()=>enhance(imgCanvas);imgBg.onclick=()=>removeBg(imgCanvas);imgFace.onclick=()=>blurFaces(imgCanvas);imgOcr.onclick=()=>ocrImage(imgCanvas,imgOutput);imgInpaint.onclick=()=>{imgPrompt.value="Remove the unwanted object and reconstruct the background naturally.";imgAI.click()};imgOutpaint.onclick=()=>{imgPrompt.value="Expand beyond the original borders and continue the scene naturally.";imgAI.click()};imgCompare.onclick=compareImages;imgAI.onclick=()=>aiEdit(imgCanvas,imgPrompt.value,imgOutput);imgDownload.onclick=()=>downloadUrl("nexus-edited.png",imgCanvas.toDataURL("image/png"));imgLibrary.onclick=()=>saveGeneratedImage(imgCanvas.toDataURL("image/png"),"Edited image")}
  async function loadCanvas(f,c){if(!f)return;const i=await image(f);c.width=i.naturalWidth;c.height=i.naturalHeight;c.getContext("2d").drawImage(i,0,0)}function enhance(c){const x=c.getContext("2d"),d=x.getImageData(0,0,c.width,c.height);for(let i=0;i<d.data.length;i+=4)for(let q=0;q<3;q++){let v=(d.data[i+q]-128)*1.12+135;d.data[i+q]=Math.max(0,Math.min(255,v))}x.putImageData(d,0,0)}function removeBg(c){const x=c.getContext("2d"),d=x.getImageData(0,0,c.width,c.height),s=[[0,0],[c.width-1,0],[0,c.height-1],[c.width-1,c.height-1]].map(([a,b])=>{const i=(b*c.width+a)*4;return[d.data[i],d.data[i+1],d.data[i+2]]}),bg=s.reduce((a,z)=>a.map((v,i)=>v+z[i]/4),[0,0,0]);for(let i=0;i<d.data.length;i+=4){const k=Math.hypot(d.data[i]-bg[0],d.data[i+1]-bg[1],d.data[i+2]-bg[2]);if(k<55)d.data[i+3]=0;else if(k<100)d.data[i+3]=Math.round(255*(k-55)/45)}x.putImageData(d,0,0)}
  async function blurFaces(c){const x=c.getContext("2d");if(!("FaceDetector" in window)){const w=c.width*.28,h=c.height*.28,a=(c.width-w)/2,b=c.height*.15;x.filter="blur(20px)";x.drawImage(c,a,b,w,h,a,b,w,h);x.filter="none";return toast("FaceDetector unavailable; central area blurred.")}const faces=await new FaceDetector({fastMode:true,maxDetectedFaces:10}).detect(c);faces.forEach(f=>{const b=f.boundingBox,p=12,a=Math.max(0,b.x-p),y=Math.max(0,b.y-p),w=Math.min(c.width-a,b.width+p*2),h=Math.min(c.height-y,b.height+p*2);x.filter="blur(22px)";x.drawImage(c,a,y,w,h,a,y,w,h);x.filter="none"});toast(`${faces.length} face(s) blurred.`)}
  async function ocrImage(c,o){o.textContent="Loading OCR…";await script("https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js");o.textContent=(await Tesseract.recognize(c,"eng",{logger:()=>{}})).data.text||"No text detected."}async function aiEdit(c,p,o){if(!p.trim())return toast("Enter an edit instruction.","error");o.textContent="Sending to editor…";try{const d=await api("/api/image-edit",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({image:c.toDataURL("image/png"),prompt:p})});if(d.dataURI)await loadCanvas(dataFile(d.dataURI,"edited.png"),c);o.textContent=d.result||"Edit complete."}catch(e){o.textContent=e.message}}
  function compareImages(){const i=document.createElement("input");i.type="file";i.accept="image/*";i.multiple=true;i.onchange=async()=>{if(i.files.length<2)return toast("Choose two images.","error");const a=await image(i.files[0]),b=await image(i.files[1]),c=document.createElement("canvas");c.width=Math.max(a.width,b.width)*2;c.height=Math.max(a.height,b.height);const x=c.getContext("2d");x.fillStyle="#fff";x.fillRect(0,0,c.width,c.height);x.drawImage(a,0,0,c.width/2,c.height);x.drawImage(b,c.width/2,0,c.width/2,c.height);c.toBlob(async blob=>{await window.NEXUS_APP?.handleFile?.(new File([blob],"image-comparison.png",{type:"image/png"}));window.NEXUS_APP?.setPrompt?.("Compare these two images side by side. Describe similarities, differences, quality, text and objects.");close()},"image/png")};i.click()}

  function security(el){el.innerHTML=`<div class="pro-grid two"><form class="pro-card pro-stack" id="resetForm"><h3>Forgot password</h3><label class="pro-field"><span>Email</span><input id="resetEmail" type="email" required></label><button class="pro-primary">Send reset link</button><p>Requires RESEND_API_KEY and EMAIL_FROM.</p></form><form class="pro-card pro-stack" id="verifyForm"><h3>Email verification</h3><label class="pro-field"><span>Email</span><input id="verifyEmail" type="email" required></label><button class="pro-primary">Send verification link</button></form></div><div class="pro-section" style="margin-top:18px"><div class="pro-section-head"><h3>Active login sessions</h3><button class="pro-secondary" id="refreshSessions">Refresh</button></div><div class="pro-list" id="sessionList"></div></div>`;resetForm.onsubmit=e=>secReq(e,"/api/auth/request-reset",{email:resetEmail.value});verifyForm.onsubmit=e=>secReq(e,"/api/auth/request-verification",{email:verifyEmail.value});refreshSessions.onclick=()=>sessions(sessionList);sessions(sessionList);tokens()}
  async function secReq(e,url,p){e.preventDefault();try{p.turnstileToken=window.NEXUS_AUTH_UI?.getTurnstileToken?.()||"";toast((await api(url,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p)})).message||"Done") }catch(x){toast(x.message,"error")}finally{window.NEXUS_AUTH_UI?.resetTurnstile?.()}}async function sessions(l){l.innerHTML='<div class="pro-status">Loading…</div>';try{const d=await api("/api/auth/sessions");l.innerHTML="";if(!d.sessions?.length)l.innerHTML='<div class="pro-status">Sign in to view sessions.</div>';d.sessions?.forEach(s=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(s.device||"Unknown device")}</strong><small>${esc(s.ip||"")} · ${esc(s.country||"")} · ${dateTime(s.createdAt)}</small></div><button class="pro-danger">Revoke</button>`;r.querySelector("button").onclick=async()=>{await api("/api/auth/sessions",{method:"DELETE",headers:{"Content-Type":"application/json"},body:JSON.stringify({sessionId:s.id})});sessions(l)};l.appendChild(r)})}catch(e){l.innerHTML=`<div class="pro-status error">${esc(e.message)}</div>`}}
  async function tokens(){const url=new URL(location.href),reset=url.searchParams.get("reset"),verify=url.searchParams.get("verify");if(verify)try{await api("/api/auth/verify-email",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({token:verify})});toast("Email verified.")}catch(e){toast(e.message,"error")}if(reset){const pass=prompt("Enter a new password (8+ characters):");if(pass)try{await api("/api/auth/reset-password",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({token:reset,password:pass})});toast("Password changed.")}catch(e){toast(e.message,"error")}}if(reset||verify){url.searchParams.delete("reset");url.searchParams.delete("verify");history.replaceState({},"",url.pathname+(url.searchParams.size?`?${url.searchParams}`:"")+url.hash)}}

  async function admin(el){const token=sessionStorage.getItem("nexusAdminToken")||"";let d;try{d=await api("/api/admin-pro",{headers:token?{"X-Admin-Token":token}:{}})}catch(e){if(e.message.includes("Admin")){const t=prompt("Admin token:");if(!t){el.innerHTML='<div class="pro-status warn">Admin access required.</div>';return}sessionStorage.setItem("nexusAdminToken",t);return admin(el)}el.innerHTML=`<div class="pro-status error">${esc(e.message)}</div>`;return}const max=Math.max(1,...(d.byFeature||[]).map(x=>+x.count||0));el.innerHTML=`<div class="pro-grid four">${metric("Users",d.users)}${metric("Blocked",d.blockedUsers)}${metric("Requests today",d.requestsToday)}${metric("Reports",d.openReports)}${metric("Errors",d.errorsToday)}${metric("Tasks",d.tasks)}${metric("Projects",d.projects)}${metric("Files",d.files)}</div><div class="pro-grid two" style="margin-top:16px"><div class="pro-card"><h3>Maintenance and limits</h3><div class="pro-buttons"><button class="pro-secondary" id="maint">${d.maintenance?"Disable maintenance":"Enable maintenance"}</button><button class="pro-secondary" id="backup">Download backup</button></div><label class="pro-field" style="margin-top:10px"><span>Default daily limit</span><input id="limit" type="number" value="${d.defaultTokenLimit||50000}"></label><button class="pro-primary" id="saveLimit" style="margin-top:8px">Save limit</button></div><div class="pro-card"><h3>API usage graphs</h3><div class="pro-stack">${(d.byFeature||[]).map(x=>`<div class="usage-bar"><span>${esc(x.feature)}</span><i style="--p:${Math.round(+x.count/max*100)}%"></i><b>${x.count}</b></div>`).join("")||"<p>No usage.</p>"}</div></div></div><div class="pro-section" style="margin-top:16px"><div class="pro-section-head"><h3>User management</h3><input id="userSearch" placeholder="Search"></div><div class="pro-list" id="users"></div></div><div class="pro-section"><div class="pro-section-head"><h3>Reports and moderation</h3></div><div class="pro-list" id="reports"></div></div><div class="pro-section"><div class="pro-section-head"><h3>Recent errors</h3></div><div class="pro-preview">${esc((d.errors||[]).map(x=>`${dateTime(x.createdAt)} · ${x.route}\n${x.message}`).join("\n\n")||"No errors.")}</div></div>`;const draw=()=>{const q=userSearch.value.toLowerCase();users.innerHTML="";(d.userList||[]).filter(u=>!q||`${u.email} ${u.displayName}`.toLowerCase().includes(q)).forEach(u=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(u.displayName)} · ${esc(u.email)}</strong><small>${esc(u.plan)} · ${u.blocked?"BLOCKED":"active"} · ${u.tokensToday||0} today</small></div><div class="pro-buttons"><button class="pro-secondary block">${u.blocked?"Unblock":"Block"}</button><button class="pro-secondary lim">Limit</button></div>`;r.querySelector(".block").onclick=()=>adm({action:u.blocked?"unblock":"block",userId:u.id}).then(()=>admin(el));r.querySelector(".lim").onclick=()=>{const x=prompt("Daily limit:",u.tokenLimit||"50000");if(x)adm({action:"limit",userId:u.id,tokenLimit:+x}).then(()=>admin(el))};users.appendChild(r)})};userSearch.oninput=draw;draw();if(!(d.reports||[]).length)reports.innerHTML='<div class="pro-status">No open reports.</div>';d.reports?.forEach(x=>{const r=document.createElement("div");r.className="pro-list-item";r.innerHTML=`<div><strong>${esc(x.reason)}</strong><small>${esc(x.content).slice(0,220)}</small></div><button class="pro-success">Resolve</button>`;r.querySelector("button").onclick=()=>adm({action:"resolve-report",reportId:x.id}).then(()=>admin(el));reports.appendChild(r)});maint.onclick=()=>adm({action:"maintenance",enabled:!d.maintenance}).then(()=>admin(el));saveLimit.onclick=()=>adm({action:"default-limit",tokenLimit:+limit.value}).then(()=>toast("Limit saved."));backup.onclick=async()=>download("nexus-backup.json",JSON.stringify(await api("/api/admin-pro?action=backup",{headers:{"X-Admin-Token":sessionStorage.getItem("nexusAdminToken")||""}}),null,2),"application/json")}

  function interfaceView(el){const u=load(K.ui,{language:"en",accent:"#7c5cff",fontScale:1,compact:false});el.innerHTML=`<div class="pro-grid two"><form class="pro-card pro-stack" id="uiForm"><h3>Appearance and language</h3><label class="pro-field"><span>Language</span><select id="uiLang"><option value="en" ${u.language==="en"?"selected":""}>English</option><option value="hi" ${u.language==="hi"?"selected":""}>हिन्दी</option></select></label><label class="pro-field"><span>Accent</span><input id="uiAccent" type="color" value="${attr(u.accent)}"></label><label class="pro-field"><span>Font scale</span><input id="uiScale" type="range" min=".85" max="1.25" step=".05" value="${u.fontScale}"></label><label><input id="uiCompact" type="checkbox" ${u.compact?"checked":""}> Compact interface</label><button class="pro-primary">Apply</button></form><div class="pro-card"><h3>Responsive controls</h3><div class="pro-buttons"><button class="pro-secondary" id="toggleSide">Toggle sidebar</button><button class="pro-secondary" id="installApp">Install app</button><button class="pro-secondary" id="clearCache">Refresh cache</button></div><p style="margin-top:12px">Mobile swipe-right opens the sidebar. Tablet layout uses two columns.</p></div></div><div class="pro-section" style="margin-top:17px"><div class="pro-section-head"><h3>Keyboard shortcuts</h3></div><table class="shortcut-table"><tr><td>New conversation</td><td><kbd>Ctrl N</kbd></td></tr><tr><td>Command palette</td><td><kbd>Ctrl K</kbd></td></tr><tr><td>Projects</td><td><kbd>Ctrl Shift P</kbd></td></tr><tr><td>Library</td><td><kbd>Ctrl Shift L</kbd></td></tr><tr><td>Send</td><td><kbd>Enter</kbd></td></tr></table></div>`;uiForm.onsubmit=e=>{e.preventDefault();localStorage.setItem(K.ui,JSON.stringify({language:uiLang.value,accent:uiAccent.value,fontScale:+uiScale.value,compact:uiCompact.checked}));applyUI();toast("Interface updated.")};toggleSide.onclick=()=>document.body.classList.toggle("sidebar-collapsed");installApp.onclick=()=>window.NEXUS_ADVANCED?.open?.("install");clearCache.onclick=async()=>{for(const x of await caches.keys())await caches.delete(x);location.reload()}}
  function applyUI(){const u=load(K.ui,{language:"en",accent:"#7c5cff",fontScale:1,compact:false});document.documentElement.dataset.uiLanguage=u.language;document.documentElement.style.setProperty("--pro-accent",u.accent);document.documentElement.style.fontSize=`${u.fontScale*100}%`;document.body.classList.toggle("compact-ui",u.compact);const l=u.language==="hi"?{n:"नई बातचीत",s:"बातचीत खोजें"}:{n:"New conversation",s:"Search conversations"},n=document.querySelector("#newChatButton span:nth-child(2)"),s=document.getElementById("chatSearchInput");if(n)n.textContent=l.n;if(s)s.placeholder=l.s}
  function gestures(){let x=0,y=0;document.addEventListener("touchstart",e=>{x=e.touches[0].clientX;y=e.touches[0].clientY},{passive:true});document.addEventListener("touchend",e=>{const dx=e.changedTouches[0].clientX-x,dy=Math.abs(e.changedTouches[0].clientY-y);if(dy>70)return;if(x<25&&dx>80)sidebar?.classList.add("open");if(dx<-90)sidebar?.classList.remove("open")},{passive:true})}

  function getActiveProjectId(){return localStorage.getItem(K.active)||""}function setActive(id){localStorage.setItem(K.active,id||"")}function activeProject(){return S.projects.find(p=>p.id===getActiveProjectId())||null}function getProjectContext(id){const p=S.projects.find(x=>x.id===id);return p?`Project: ${p.name}\nInstructions: ${p.instructions||"None"}\nProject memory: ${p.memory||"None"}`:""}function saveProjects(){localStorage.setItem(K.projects,JSON.stringify(S.projects))}function saveTasks(){localStorage.setItem(K.tasks,JSON.stringify(S.tasks))}
  async function syncProject(p){if(!S.account?.authenticated)return;try{await api("/api/projects",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"save",project:p})})}catch{}}async function syncTask(t){if(!S.account?.authenticated)return;try{await api("/api/tasks",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"save",task:t})})}catch{}}async function delCloud(url,id){if(!S.account?.authenticated)return;try{await api(`${url}?id=${encodeURIComponent(id)}`,{method:"DELETE"})}catch{}}
  function watchTasks(){setInterval(checkTasks,30000);checkTasks()}function checkTasks(){const now=Date.now();S.tasks.filter(t=>t.enabled&&t.nextRun<=now).forEach(t=>{notify(t.name,t.type==="reminder"?t.prompt:"AI task is due. Open Scheduled Tasks to run it.");t.lastRun=now;advance(t)});saveTasks()}function advance(t){if(t.schedule==="daily")t.nextRun+=86400000;else if(t.schedule==="weekly")t.nextRun+=604800000;else t.enabled=false}async function notifyPermission(){if(!("Notification" in window))return toast("Notifications unsupported.","error");toast(`Notification permission: ${await Notification.requestPermission()}`)}function notify(title,body){if("Notification" in window&&Notification.permission==="granted")new Notification(title,{body,icon:"/assets/logo-icon.png?v=15.1.0"});else toast(`${title}: ${body}`)}
  async function ingestFile(f,a=null){if(!f)return;const n=f.name.toLowerCase(),category=f.type.startsWith("image/")?"image":n.endsWith(".pdf")?"pdf":/\.(js|ts|py|java|c|cpp|html|css|sql|json|xml|yaml|yml)$/i.test(n)?"code":"file";let text=a?.text||"",dataUrl=a?.dataUrl||"";if(!text&&!dataUrl&&f.size<2e6){if(f.type.startsWith("image/"))dataUrl=await fileUrl(f);else try{text=await f.text()}catch{}}await saveLibraryItem({category,name:f.name,mime:f.type,size:f.size,text:text.slice(0,150000),dataUrl,createdAt:Date.now(),projectId:getActiveProjectId()})}async function saveGeneratedImage(dataUrl,prompt="Generated image"){await saveLibraryItem({category:"image",name:`generated-${Date.now()}.png`,mime:"image/png",size:dataUrl.length,text:prompt,dataUrl,createdAt:Date.now(),projectId:getActiveProjectId()});toast("Saved to Library.")}async function saveLibraryItem(x){return libPut({id:x.id||crypto.randomUUID(),...x,createdAt:x.createdAt||Date.now()})}
  async function rateMessage(m,r){try{await api("/api/feedback",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({rating:r,message:m.content.slice(0,4000)})});toast("Feedback recorded.")}catch(e){toast(e.message,"error")}}async function reportMessage(m){const reason=prompt("Why are you reporting this answer?","Incorrect or unsafe");if(!reason)return;try{await api("/api/report",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({reason,content:m.content.slice(0,8000),chatId:window.NEXUS_APP?.getActiveChat?.()?.id||""})});toast("Report submitted.")}catch(e){toast(e.message,"error")}}function branchFromMessage(i){window.NEXUS_APP?.forkChatAt?.(i);toast("Conversation branch created.");close()}function addToCompare(m){S.compare.unshift({id:crypto.randomUUID(),content:m.content,createdAt:Date.now(),chatTitle:window.NEXUS_APP?.getActiveChat?.()?.title||""});S.compare=S.compare.slice(0,6);localStorage.setItem(K.compare,JSON.stringify(S.compare));toast("Added to comparison.")}function compareView(){if(!S.compare.length)return toast("Use Compare on answers first.","error");proTitle.textContent="Compare Answers";proView.innerHTML=`<div class="compare-grid">${S.compare.map(x=>`<div class="pro-card compare-answer"><h3>${esc(x.chatTitle||"Answer")}</h3>${esc(x.content)}</div>`).join("")}</div><div class="pro-buttons" style="margin-top:12px"><button class="pro-danger" id="clearCompare">Clear</button></div>`;clearCompare.onclick=()=>{S.compare=[];localStorage.setItem(K.compare,"[]");render("dashboard")}}
  async function config(){try{S.config=await api("/api/config")}catch{}}async function account(){try{S.account=await api("/api/auth/me")}catch{S.account={authenticated:false}};if(S.account.authenticated){try{const p=await api("/api/projects"),m=new Map(S.projects.map(x=>[x.id,x]));p.projects?.forEach(x=>m.set(x.id,{...m.get(x.id),...x}));S.projects=[...m.values()];saveProjects()}catch{}try{const t=await api("/api/tasks"),m=new Map(S.tasks.map(x=>[x.id,x]));t.tasks?.forEach(x=>m.set(x.id,{...m.get(x.id),...x}));S.tasks=[...m.values()];saveTasks()}catch{}}}
  function metric(n,v){return`<div class="pro-card admin-metric"><strong>${Number(v||0).toLocaleString()}</strong><p>${esc(n)}</p></div>`}async function adm(p){return api("/api/admin-pro",{method:"POST",headers:{"Content-Type":"application/json","X-Admin-Token":sessionStorage.getItem("nexusAdminToken")||""},body:JSON.stringify(p)})}
  function vec(t){const v=new Array(256).fill(0),tokens=String(t).toLowerCase().match(/[a-z0-9\u0900-\u097f]{2,}/g)||[];tokens.forEach(x=>{let h=2166136261;for(const c of x){h^=c.codePointAt(0);h=Math.imul(h,16777619)}v[(h>>>0)%v.length]++});const n=Math.hypot(...v)||1;return v.map(x=>x/n)}function cos(a,b){let s=0;for(let i=0;i<a.length;i++)s+=a[i]*b[i];return s}
  function catIcon(c){return({image:"🖼",pdf:"PDF",code:"⌘",shared:"🔗",favorite:"★",video:"🎬",music:"♫",file:"📄"})[c]||"▣"}function dataFile(u,n){const [m,d]=u.split(","),mime=m.match(/:(.*?);/)?.[1]||"application/octet-stream",b=Uint8Array.from(atob(d),x=>x.charCodeAt(0));return new File([b],n,{type:mime})}function fileUrl(f){return new Promise((r,j)=>{const x=new FileReader;x.onload=()=>r(x.result);x.onerror=j;x.readAsDataURL(f)})}function image(f){return new Promise((r,j)=>{const i=new Image;i.onload=()=>r(i);i.onerror=j;i.src=URL.createObjectURL(f)})}function downloadUrl(n,u){const a=document.createElement("a");a.download=n;a.href=u;a.click()}function download(n,t,m="text/plain"){const u=URL.createObjectURL(new Blob([t],{type:m})),a=document.createElement("a");a.href=u;a.download=n;a.click();URL.revokeObjectURL(u)}function localTime(d){const p=n=>String(n).padStart(2,"0");return`${d.getFullYear()}-${p(d.getMonth()+1)}-${p(d.getDate())}T${p(d.getHours())}:${p(d.getMinutes())}`}function date(v){return new Date(v||Date.now()).toLocaleDateString()}function dateTime(v){return new Date(v||Date.now()).toLocaleString()}function bytes(b=0){if(!b)return"0 B";const u=["B","KB","MB","GB"],i=Math.min(Math.floor(Math.log(b)/Math.log(1024)),3);return`${(b/1024**i).toFixed(i?1:0)} ${u[i]}`}function esc(v=""){return String(v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"})[c])}function attr(v=""){return esc(v)}function load(k,f){try{return JSON.parse(localStorage.getItem(k))??f}catch{return f}}function toast(m,t=""){window.NEXUS_APP?.showToast?.(m,t)}async function api(u,o={}){const r=await fetch(u,o),d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.error||`Request failed (${r.status})`);return d}function script(src){return new Promise((r,j)=>{if([...document.scripts].some(s=>s.src===src))return r();const x=document.createElement("script");x.src=src;x.onload=r;x.onerror=j;document.head.appendChild(x)})}
  function db(){return new Promise((r,j)=>{const q=indexedDB.open("nexus-v9-library",1);q.onupgradeneeded=()=>q.result.createObjectStore("items",{keyPath:"id"});q.onsuccess=()=>r(q.result);q.onerror=()=>j(q.error)})}async function libPut(x){const d=await db();return new Promise((r,j)=>{const t=d.transaction("items","readwrite");t.objectStore("items").put(x);t.oncomplete=()=>r(x);t.onerror=()=>j(t.error)})}async function libList(){const d=await db();return new Promise((r,j)=>{const q=d.transaction("items").objectStore("items").getAll();q.onsuccess=()=>r(q.result.sort((a,b)=>b.createdAt-a.createdAt));q.onerror=()=>j(q.error)})}async function libDelete(id){const d=await db();return new Promise((r,j)=>{const t=d.transaction("items","readwrite");t.objectStore("items").delete(id);t.oncomplete=r;t.onerror=()=>j(t.error)})}
})();
